import {
	SET_POSTS,
	SET_TOPIC,
	SET_POST,
	POST,
	DELETE_POST,
	POST_COMMENTS,
	LOADING_DATA } from '../types'

const initialState = {
	posts: [],
	topic: [],
	post: {},
	loading: false,
};

export default function(state = initialState, action) {
	switch (action.type) {
		case SET_POSTS:
			return {
				...state,
				posts: action.payload,
				loading: false
			};
		case SET_TOPIC:
			return {
				...state,
				topic: action.payload,
				loading: false
			};
		case SET_POST:
			return {
				...state,
				post: action.payload
			};
		case POST:
			return {
				...state,
				posts: [ action.payload, ...state.posts ]
			};
		case DELETE_POST:
			let index = state.posts.findIndex(
				(post) => post.postsid === action.payload
				);
			state.posts.splice(index, 1);
			return {
				...state
			};
		case POST_COMMENTS:
			return {
				...state,
				post: {
					...state.post,
					comments: [
						action.payload,
						...state.post.comments
					]
				}
			};
		case LOADING_DATA:
			return {
				...state,
				loading: true
			};
		default:
			return state;
	}
}