import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';

// Material
import Grid from '@material-ui/core/Grid';
import Typography from '@material-ui/core/Typography';
import Button from '@material-ui/core/Button';
import TextField from '@material-ui/core/TextField';
import InputAdornment from '@material-ui/core/InputAdornment';

import { makeStyles, createStyles, useTheme } from '@material-ui/core/styles';
import useMediaQuery from '@material-ui/core/useMediaQuery';

const useStyles = makeStyles((theme: Theme) => createStyles({
	...theme.spreadThis,
	titleCont: {
		textTransform: 'uppercase',
		textAlign: 'center',
		fontFamily: '"Helvetica Compressed"',
		margin: '2rem 0'
	},
	imgClass: {
		objectFit: 'cover',
		minWidth: '100%',
		height: '100px',
		maxWidth: '100%',
		[theme.breakpoints.down('sm')]: {
			height: '150px'
		},
		[theme.breakpoints.down('xs')]: {
			height: '100px'
		}
	},
	gridClass: {
		margin: '0',
		[theme.breakpoints.up('md')]: {
			maxWidth: '22.5%'
		},
		[theme.breakpoints.down('sm')]: {
			maxWidth: '45%'
		}
	},
	hrHome: {
		marginTop: '2.5rem',
		width: '100%'
	},
	subClass: {
		textAlign: 'center',
		display: 'flex',
		justifyContent: 'center',
		flexDirection: 'column',
		alignItems: 'center',
		height: '100%',
	},
}));
  
export default function CustomNews(props) {

  const [ subscribe, setSubscribe ] = useState('');

	const news = props.news.filter(n => n.topic !== 'video');
	const recommend = news.filter(n => n.recommended === true).slice(0, 4);
	const liked = news.sort((a, b) => b.commentCount - a.commentCount).slice(0, 4);

  const theme = useTheme();
  const classes = useStyles(props);
  const matches = useMediaQuery(theme.breakpoints.down('sm'));

  const handleSubmit = (evt) => {
		// do something
  }

	return (
		<Grid container style={{ marginBottom: '5rem' }} justify="space-between">
			<Grid xs={12} md={8}>
				<div>
					<Typography variant="h5" className={classes.titleCont}>Editors Picks</Typography>
					<Grid justify="space-around" container>
						{
							recommend.map((data, i) => (
								<Grid xs={6} md={3} className={classes.gridClass}>
									<Link key={i} className={classes.linkClass} key={i} to={`/story/${data.id}`}>
										<img src={data.postImage} className={classes.imgClass} alt="recommended" />
										<Typography variant="subtitle2"><strong>{data.title}</strong></Typography>
									</Link>
								</Grid>
							))
						}
					</Grid>
				</div>
				<hr className={`${classes.hrTop} ${classes.hrHome}`} />
				<div>
					<Typography variant="h5" className={classes.titleCont}>Most Comments</Typography>
					<Grid justify="space-around" container>
						{
							liked.map((data, i) => (
								<Grid xs={6} md={3} className={classes.gridClass}>
									<Link key={i} className={classes.linkClass} key={i} to={`/story/${data.id}`}>
										<img src={data.postImage} className={classes.imgClass} alt="recommended" />
										<Typography variant="subtitle2"><strong>{data.title}</strong></Typography>
									</Link>
								</Grid>
							))
						}
					</Grid>
				</div>
			</Grid>
			{
				!matches &&
				<Grid xs={12} md={4} className={classes.subClass}>
					<Typography variant='h5' style={{ marginBottom: '1rem' }} className={classes.titleCont}><em>Weekly News Updates</em></Typography>
					<Typography variant='body1'>Subscribe to get the week's most<br /> important news.</Typography>
				  <TextField
				  	color="secondary"
				  	value={subscribe}
				  	onChange={e => setSubscribe(e.target.value)}
				  	onClick={handleSubmit}
				  	placeholder="email@address.com"
				  	className='textField'
				  	variant="outlined"
		        InputProps={{
		          endAdornment: (
		            <InputAdornment position="end">
		              <Button>Subscribe</Button>
		            </InputAdornment>
		          ),
		        }}
			  	/>
				</Grid>
			}
		</Grid>
	);
}
